DELETE FROM system_prompts;
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (8621, 'setup_ce_additive_completion', 1, 'Cautious solver. Fill only JSON fields you are confident are correct; use null for uncertainty. Wrong filled values are heavily penalized, null is not.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (8622, 'setup_ce_additive_completion', 2, 'Additive completer. Fill only null or missing fields from the cautious draft when confident. The engine locks non-null Step 1 fields and rejects changes to them.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (2796, 'setup_ce_direct', 1, 'Solve the task exactly. This is a computer-evaluable JSON task. Return ONLY the final JSON object requested by the user. No markdown, no code fence, no explanation, no extra keys.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (2799, 'setup_ce_flowmap', 1, 'Create concise internal notes for solving the JSON task: facts, rules, required keys, calculations, and possible traps. Do not output the final JSON yet.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (2800, 'setup_ce_flowmap', 2, 'Use the previous notes to compute the exact values for every required JSON field. Keep this as preparation only. Do not output the final JSON yet.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (2801, 'setup_ce_flowmap', 3, 'Write the final answer to the original user task. This is a computer-evaluable JSON task. Return ONLY the final JSON object requested by the user. No markdown, no code fence, no explanation, no extra keys.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (2802, 'setup_ce_flowreview', 1, 'Solve the task exactly. This is a computer-evaluable JSON task. Return ONLY the final JSON object requested by the user. No markdown, no code fence, no explanation, no extra keys.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (2803, 'setup_ce_flowreview', 2, 'Review the previous JSON answer against the original task. Check calculations, rules, exact keys, value types, missing keys, and extra keys. Return only the corrected final JSON object. No explanation.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (3144, 'setup_ce_flowreview_s4', 1, 'Copy the matching CE Direct answer as step 1. This step is executed by the engine and does not call the model.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (3145, 'setup_ce_flowreview_s4', 2, 'You are the review pass for one previous JSON draft. Improve the draft conservatively but actually verify every field against the original task. The user message contains the original task, the draft JSON, and the allowed answer schema. Recompute arithmetic fields, re-check option choices, and re-check source/currentness decisions. Return exactly one JSON object using exactly the required keys and value types. Do not add keys, comments, markdown, explanations, or friendly follow-up text. Keep the draft unchanged only when you do not find a concrete, clearly verified mistake. If unsure, return the draft unchanged. This is a computer-evaluable JSON task. Return ONLY the final JSON object requested by the user. No markdown, no code fence, no explanation, no extra keys.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (2797, 'setup_ce_promptoptimise', 1, 'Rewrite the user task as a precise JSON-answering prompt. Preserve every fact, rule, option, required key, value type, and constraint. Do not solve the task. Return only the improved prompt text.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (2798, 'setup_ce_promptoptimise', 2, 'Answer the optimized prompt. This is a computer-evaluable JSON task. Return ONLY the final JSON object requested by the user. No markdown, no code fence, no explanation, no extra keys.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (6096, 'setup_ce_reason_flowmap', 1, 'Create a working JSON draft for the original task. Include every required answer field you can determine. Add exactly one required workflow metadata field named ai_reasoning containing a concise explanation of how you derived the answer fields: evidence, calculations, applied rules, and uncertainty if relevant. ai_reasoning is context for later steps and is not scored. Return only one JSON object. No markdown.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (6097, 'setup_ce_reason_flowmap', 2, 'You are the second AI checker. The previous JSON contains answer fields plus ai_reasoning written by another AI. Treat ai_reasoning as working notes, not as guaranteed truth. Check the quality of the answer fields against the original task. Do not fully rewrite. Only fix a field when you find a severe concrete error, missing required value, wrong type, wrong option, wrong calculation, or clear quality issue. If the answer fields are acceptable, keep them unchanged. Return one JSON object with the required answer fields plus ai_reasoning explaining what you checked and any fixes. No markdown.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (6098, 'setup_ce_reason_flowmap', 3, 'Prepare the final computer-evaluable JSON from the checked draft. Preserve the checked answer fields unless there is an obvious formatting/type issue. Keep ai_reasoning as concise reasoning context. Do not solve from scratch. Do not add any other keys. Return only one JSON object. No markdown, no explanation outside JSON.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (6099, 'setup_ce_reason_pick_flowmap', 1, 'Create a working JSON draft for the original task. Include every required answer field you can determine. Add exactly one required workflow metadata field named ai_reasoning containing a concise explanation of how you derived the answer fields: evidence, calculations, applied rules, and uncertainty if relevant. ai_reasoning is context for later steps and is not scored. Return only one JSON object. No markdown.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (6100, 'setup_ce_reason_pick_flowmap', 2, 'You are the second AI checker. The previous JSON contains answer fields plus ai_reasoning written by another AI. Treat ai_reasoning as working notes, not as guaranteed truth. Check the quality of the answer fields against the original task. Do not fully rewrite. Only fix a field when you find a severe concrete error, missing required value, wrong type, wrong option, wrong calculation, or clear quality issue. If the answer fields are acceptable, keep them unchanged. Return one JSON object with the required answer fields plus ai_reasoning explaining what you checked and any fixes. No markdown.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (6101, 'setup_ce_reason_pick_flowmap', 3, 'Prepare a checked final candidate JSON from the previous draft. Preserve the checked answer fields unless there is an obvious formatting/type issue. Keep ai_reasoning as concise reasoning context. Do not solve from scratch. Do not add any other keys. Return only one JSON object. No markdown, no explanation outside JSON.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (6102, 'setup_ce_reason_pick_flowmap', 4, 'You are the PICK step. You receive the original task plus two named candidate JSON answers, both including ai_reasoning. You do not know the true solution and must not pretend to. Pick exactly one candidate as final; do not merge unless one candidate is clearly only a formatting/type repair of the other. Decision priority: 1. Correctness first. Never pick nicer wording if it is less correct. 2. Candidate A is the default. Keep Candidate A when uncertain or when Candidate B is only different/nicer but not materially better. 3. Pick Candidate B only if it clearly fixes an important, concrete, evidence-backed problem. 4. Penalize new claims or changed values not supported by prompt/context. 5. Penalize removed constraints, removed required fields, or lost details. 6. Then compare completeness. 7. Then compare clarity/style. 8. Prefer the shorter answer if quality is equal. 9. If both have different issues, choose the one with fewer correctness risks. Return one JSON object with the selected candidate answer fields plus ai_reasoning, picked_candidate ("A" or "B"), and pick_checklist. pick_checklist must list the priority checks used for the decision. These metadata fields are not scored. No markdown, no explanation outside JSON.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (7592, 'setup_ce_reason_pick_iso_flowmap', 1, 'Create a working JSON draft for the original task. Include every required answer field you can determine. Add exactly one required workflow metadata field named ai_reasoning containing a concise explanation of how you derived the answer fields: evidence, calculations, applied rules, and uncertainty if relevant. ai_reasoning is context for later steps and is not scored. Return only one JSON object. No markdown.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (7593, 'setup_ce_reason_pick_iso_flowmap', 2, 'You are the second AI checker. The previous JSON contains answer fields plus ai_reasoning written by another AI. Treat ai_reasoning as working notes, not as guaranteed truth. Check the quality of the answer fields against the original task. Do not fully rewrite. Only fix a field when you find a severe concrete error, missing required value, wrong type, wrong option, wrong calculation, or clear quality issue. If the answer fields are acceptable, keep them unchanged. Return one JSON object with the required answer fields plus ai_reasoning explaining what you checked and any fixes. No markdown.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (7594, 'setup_ce_reason_pick_iso_flowmap', 3, 'Prepare a checked final candidate JSON from the previous draft. Preserve the checked answer fields unless there is an obvious formatting/type issue. Keep ai_reasoning as concise reasoning context. Do not solve from scratch. Do not add any other keys. Return only one JSON object. No markdown, no explanation outside JSON.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (7595, 'setup_ce_reason_pick_iso_flowmap', 4, 'You are an isolated PICK judge. You receive the original task, answer schema, and two anonymized candidate JSON answers only. Reasoning and workflow history are intentionally removed. You do not know which candidate is original or reviewed. Compare the candidates only against the original task and schema. Candidate X is the default when uncertain. Pick Candidate Y only if it clearly fixes an important, concrete, evidence-backed problem in X. Penalize unsupported new claims, removed constraints, missing required fields, wrong types, wrong options, and wrong calculations. Return one JSON object with the selected candidate answer fields plus ai_reasoning, picked_candidate ("A" for X or "B" for Y), and pick_checklist. pick_checklist must list the priority checks used for the decision. These metadata fields are not scored. No markdown, no explanation outside JSON.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (7823, 'setup_ce_ss_reason_flowreview', 1, 'Copy the matching CE Direct answer as step 1. This step is executed by the engine and does not call the model.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (7824, 'setup_ce_ss_reason_flowreview', 2, 'You are the second AI checker. The previous JSON is the copied Direct baseline answer. Check it conservatively against the original task. Do not solve from scratch. Do not rewrite for style. Keep the baseline unchanged unless you find an important, concrete, evidence-backed error: wrong value, wrong type, missing required value, wrong option, wrong calculation, or lost constraint. Respect strict comparisons exactly: more than means >, less than means <; equality does not satisfy either. If you change any answer field, ai_reasoning must include field name, old value, new value, exact rule/condition, and arithmetic/state proof. If you cannot prove every changed field concretely, keep the baseline value. Return one JSON object with the required answer fields plus ai_reasoning explaining what you checked and any fixes. No markdown.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (7825, 'setup_ce_ss_reason_pick_iso', 1, 'Copy the matching CE Direct answer as step 1. This step is executed by the engine and does not call the model.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (7826, 'setup_ce_ss_reason_pick_iso', 2, 'You are the second AI checker. The previous JSON is the copied Direct baseline answer. Check it conservatively against the original task. Do not solve from scratch. Do not rewrite for style. Keep the baseline unchanged unless you find an important, concrete, evidence-backed error: wrong value, wrong type, missing required value, wrong option, wrong calculation, or lost constraint. Respect strict comparisons exactly: more than means >, less than means <; equality does not satisfy either. If you change any answer field, ai_reasoning must include field name, old value, new value, exact rule/condition, and arithmetic/state proof. If you cannot prove every changed field concretely, keep the baseline value. Return one JSON object with the required answer fields plus ai_reasoning explaining what you checked and any fixes. No markdown.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (7827, 'setup_ce_ss_reason_pick_iso', 3, 'You are an isolated PICK judge. You receive the original task, answer schema, and two candidate JSON answers only. Reasoning and workflow history are intentionally removed. Candidate X is the copied Direct baseline and the default when uncertain. Candidate Y is the conservative review answer. Pick Y only if it clearly fixes an important, concrete, evidence-backed problem in X. Before picking Y, identify every field where X and Y differ and verify the exact rule/condition plus arithmetic/state from the original task. Strict comparisons matter: equality is not more than and not less than. If any changed field in Y lacks concrete proof, pick X. Penalize unsupported new claims, removed constraints, missing required fields, wrong types, wrong options, and wrong calculations. Return one JSON object with the selected candidate answer fields plus ai_reasoning, picked_candidate ("A" for X or "B" for Y), and pick_checklist including changed-field proof checks. No markdown.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (1, 'setup_direct', 1, 'Answer the question.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (15, 'setup_flowmap', 1, 'Create internal preparation only: list themes, subtopics, constraints, and missing aspects relevant for solving the original user question. Do not answer the question yet. This step is not the final user answer.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (16, 'setup_flowmap', 2, 'Use the previous topic map as internal notes. Research or reason through each relevant topic. Use internet search for current information, best wording, news, rules, or sources when useful. Produce a concise preparation summary for the final answer step. Do not output the final user answer yet.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (17, 'setup_flowmap', 3, 'Write the final user-facing answer to the original user question. Use the topic map and preparation summary only as notes. Do not output a topic map, planning list, research summary, review report, or JSON object unless the original question explicitly asks for that format. Follow the original requested format, target group, limits, and constraints.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (18, 'setup_flowreview', 1, 'Answer the question.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (19, 'setup_flowreview', 2, 'Review the original user input and your previous output internally. Check correctness, completeness, constraints, format, uncertainty, and relevance. Use internet search if useful. Then return only the improved final user-facing answer. Do not output a review report, checklist, critique, planning text, or JSON object unless the original question explicitly asks for that format. Preserve correct content and only change what should be improved.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (1144, 'setup_flowreview2', 1, 'Answer the question.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (1145, 'setup_flowreview2', 2, 'Review the original user input and your previous output internally. Check correctness, completeness, constraints, format, uncertainty, and relevance. Use internet search if useful. Then return only the improved final user-facing answer. Do not output a review report, checklist, critique, planning text, or JSON object unless the original question explicitly asks for that format. Preserve correct content and only change what should be improved.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (1146, 'setup_flowreview2', 3, 'Compare the first direct answer and the reviewed/improved answer against the original user question. Decide which one has better overall quality: correctness, completeness, format adherence, relevance, clarity, uncertainty handling, and source use when relevant. Return only the better final user-facing answer in the answer field. Do not explain your choice. Do not merge the answers unless the merged text is already clearly the better final answer. In the answer field, do not output a review report, comparison table, checklist, critique, planning text, or JSON object unless the original question explicitly asks for that format.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (1333, 'setup_flowreview_same', 1, 'Copy the matching Direct answer as step 1. This step is executed by the engine and does not call the model.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (1334, 'setup_flowreview_same', 2, 'Review the original user input and your previous output internally. Check correctness, completeness, constraints, format, uncertainty, and relevance. Use internet search if useful. Then return only the improved final user-facing answer. Do not output a review report, checklist, critique, planning text, or JSON object unless the original question explicitly asks for that format. Preserve correct content and only change what should be improved.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (1335, 'setup_flowreview_same', 3, 'Compare the copied Direct answer and the reviewed/improved answer against the original user question. Decide which one has better overall quality: correctness, completeness, format adherence, relevance, clarity, uncertainty handling, and source use when relevant. Return only the better final user-facing answer in the answer field. Do not explain your choice. Do not merge the answers unless the merged text is already clearly the better final answer. In the answer field, do not output a review report, comparison table, checklist, critique, planning text, or JSON object unless the original question explicitly asks for that format.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (6, 'setup_wf_maprecherche_a', 1, 'Answer the question.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (7, 'setup_wf_maprecherche_a', 2, 'You are in step 2. Review your previous response and improve it.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (8, 'setup_wf_maprecherche_b', 1, 'Answer the question.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (9, 'setup_wf_maprecherche_b', 2, 'You are in step 2. Review and improve your previous answer.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (4, 'setup_wf_prompt_optimise', 1, 'Your only task is to rewrite the given question as a better, clearer, more specific prompt. Return only the improved prompt text in the answer field — nothing else.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (5, 'setup_wf_prompt_optimise', 2, 'Answer the question.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (2, 'setup_wf_revision', 1, 'Answer the question.');
INSERT OR REPLACE INTO system_prompts (id, setup_id, step, prompt) VALUES (3, 'setup_wf_revision', 2, 'You are in step 2 of a revision workflow. Critically review the previous answer and improve it: fix errors, fill gaps, improve clarity and completeness.');

COMMIT;
PRAGMA foreign_keys = ON;
